{/* app/_components/Eyebrow.tsx */}
export function Eyebrow({children, tone='muted'}: {children: React.ReactNode; tone?: 'muted'|'accent'}) {
  const color = tone === 'accent' ? 'text-[#22F0D5]' : 'text-[#9BA5A7]';
  return <p className={`text-[12px] font-medium leading-[1.2] ${color}`}>{children}</p>;
}

'use client';
import { usePathname } from 'next/navigation';

function NavLink({href, children}: {href: string; children: React.ReactNode}) {
  const pathname = usePathname();
  const active = pathname === href || pathname.startsWith(href + '/');
  return (
    <Link
      href={href}
      aria-current={active ? 'page' : undefined}
      className={`relative text-[14px] font-medium transition-colors ${active ? 'text-white after:absolute after:left-0 after:right-0 after:-bottom-[22px] after:h-px after:bg-[#22F0D5]' : 'text-[#E7EBED] hover:text-white'}`}
    >
      {children}
    </Link>
  );
}

{/* Global CTA — ONE solid cyan pill */}
<Link href="/start" className="rounded-full bg-[#22F0D5] px-4 py-1.5 text-[13px] font-medium text-black transition-colors hover:bg-[#1AD4BD]">Start</Link>

